<div class="page-title-row"><div><p class="text-muted mb-1">Fleet & equipment</p><h1>Asset Replacement Planning</h1></div></div>
<div class="row g-4"><div class="col-xl-4"><section class="portal-card"><h2>Add or update plan</h2><form method="post" action="/portal/asset-planning" class="row g-3"><?=csrf_field()?><div class="col-6"><label class="form-label">Asset type</label><select class="form-select" name="asset_type"><option value="vehicle">Vehicle</option><option value="equipment">Equipment</option></select></div><div class="col-6"><label class="form-label">Asset ID</label><input type="number" min="1" class="form-control" name="asset_id" required></div><div class="col-6"><label class="form-label">Acquisition cost</label><input type="number" step=".01" class="form-control" name="acquisition_cost" required></div><div class="col-6"><label class="form-label">Acquisition date</label><input type="date" class="form-control" name="acquisition_date"></div><div class="col-6"><label class="form-label">Useful life, months</label><input type="number" class="form-control" name="useful_life_months" value="60" required></div><div class="col-6"><label class="form-label">Salvage value</label><input type="number" step=".01" class="form-control" name="salvage_value" value="0"></div><div class="col-6"><label class="form-label">Target date</label><input type="date" class="form-control" name="replacement_target_date"></div><div class="col-6"><label class="form-label">Budget</label><input type="number" step=".01" class="form-control" name="replacement_budget"></div><div class="col-12"><label class="form-label">Notes</label><textarea class="form-control" name="notes"></textarea></div><div class="col-12"><button class="btn btn-primary">Save plan</button></div></form></section></div><div class="col-xl-8"><section class="portal-card"><h2>Replacement forecast</h2><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Asset</th><th>Cost</th><th>Book value</th><th>Target</th><th>Budget</th></tr></thead><tbody><?php foreach($plans as $p):?><tr><td><?=e(ucfirst($p['asset_type']))?> #<?=e($p['asset_id'])?></td><td>$<?=number_format((float)$p['acquisition_cost'],2)?></td><td>$<?=number_format(max(0,(float)$p['current_book_value']),2)?></td><td><?=e($p['replacement_target_date']?:'Not set')?></td><td><?=($p['replacement_budget']!==null?'$'.number_format((float)$p['replacement_budget'],2):'—')?></td></tr><?php endforeach?><tr class="<?=count($plans)?'d-none':''?>"><td colspan="5" class="text-muted">No replacement plans yet.</td></tr></tbody></table></div></section></div></div>
